import React, { useState, useEffect, useMemo } from 'react';

const ITEMS = [
    { id: 1, name: 'JavaScript Framework Guide', category: 'frontend' },
    { id: 2, name: 'Python Data Science Handbook', category: 'data' },
    { id: 3, name: 'React Performance Optimization', category: 'frontend' },
    { id: 4, name: 'Node.js Backend Architecture', category: 'backend' },
    { id: 5, name: 'SQL Query Optimization Techniques', category: 'database' },
    { id: 6, name: 'TypeScript Advanced Patterns', category: 'frontend' },
    { id: 7, name: 'Docker Container Security', category: 'devops' },
    { id: 8, name: 'GraphQL API Design', category: 'backend' },
    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

function useDebounce(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);

    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedValue(value);
        }, delay);

        return () => {
            clearTimeout(timer);
        };
    }, [value, delay]);

    return debouncedValue;
}

function escapeRegExp(str) {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function highlightMatch(text, query) {
    const trimmedQuery = query.trim();
    if (!trimmedQuery) {
        return text;
    }

    const escaped = escapeRegExp(trimmedQuery);
    const regex = new RegExp(`(${escaped})`, 'gi');
    const parts = text.split(regex).filter(part => part.length > 0);

    return parts.map((part, index) => {
        if (part.toLowerCase() === trimmedQuery.toLowerCase()) {
            return <mark key={index}>{part}</mark>;
        }
        return <React.Fragment key={index}>{part}</React.Fragment>;
    });
}

function ResourceList() {
    const [searchTerm, setSearchTerm] = useState('');
    const debouncedSearchTerm = useDebounce(searchTerm, 300);

    const trimmedSearch = searchTerm.trim();
    const isSearching = trimmedSearch.length > 0 && searchTerm !== debouncedSearchTerm;

    const debouncedTrimmed = debouncedSearchTerm.trim();
    const effectiveTerm = trimmedSearch.length === 0 ? '' : debouncedTrimmed;

    const filteredItems = useMemo(() => {
        const term = effectiveTerm.toLowerCase();
        if (!term) {
            return ITEMS;
        }
        return ITEMS.filter(item =>
            item.name.toLowerCase().includes(term)
        );
    }, [effectiveTerm]);

    return (
        <div>
            <h2>Resources</h2>
            <input
                type="text"
                placeholder="Search resources..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                aria-label="Search resources"
            />
            {isSearching && <p>Searching...</p>}
            {filteredItems.length === 0 ? (
                <p>No results found</p>
            ) : (
                <ul>
                    {filteredItems.map(item => (
                        <li key={item.id}>
                            <strong>{highlightMatch(item.name, effectiveTerm)}</strong> <span>({item.category})</span>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

export default ResourceList;
